import sys

def is_balanced(s):
    stack = []
    mapping = {")": "(", "]": "[", "}": "{"}
    for char in s:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping:
            if not stack or mapping[char] != stack.pop():
                return False
    return not stack

if __name__ == "__main__":
    input_string = sys.argv[1]
    result = 'yes' if is_balanced(input_string) else 'no'
    print(result + '\n')

import sys

def find_unbalanced_index(s):
    balance = 0
    for i, char in enumerate(s):
        if char == '(':
            balance += 1
        elif char == ')':
            balance -= 1
            if balance < 0:
                return i
    return -1

if __name__ == "__main__":
    input_string = sys.argv[1]
    result = find_unbalanced_index(input_string)
    print(result)

import sys

def longest_run(s):
    max_length = 0
    current_length = 1

    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            current_length += 1
        else:
            if current_length > max_length:
                max_length = current_length
            current_length = 1

    return max(max_length, current_length)

if __name__ == "__main__":
    input_string = sys.argv[1]
    result = longest_run(input_string)
    print(result + '\n')

import sys

def longest_even_streak(numbers):
    max_streak = 0
    current_streak = 0

    for num in numbers:
        if num % 2 == 0:
            current_streak += 1
            if current_streak > max_streak:
                max_streak = current_streak
        else:
            current_streak = 0

    return max_streak

if __name__ == "__main__":
    numbers = list(map(int, sys.argv[1].split()))
    print(longest_even_streak(numbers))

import sys

def longest_increasing_streak(nums):
    if not nums:
        return 0

    max_length = current_length = 1

    for i in range(1, len(nums)):
        if nums[i] > nums[i - 1]:
            current_length += 1
        else:
            max_length = max(max_length, current_length)
            current_length = 1

    return max(max_length, current_length)

if __name__ == "__main__":
    input_str = sys.argv[1]
    nums = list(map(int, input_str.split()))
    result = longest_increasing_streak(nums)
    print(result)

